import logo from "./logo.svg";
import "./App.css";

function App() {
    return (
        <div className="App">
            <StepCounter />
            <Counter />
        </div>
    );
}

const StepCounter = function () {
    return (
        <div className="counter-steps">
            <button type="button">-</button>
            <span>Step:</span>
            <button type="button">+</button>
        </div>
    );
};
const Counter = function () {
    return (
        <div className="counter-steps">
            <button type="button">Counter:</button>
        </div>
    );
};
export default App;
